var minimumPushes = function(word) {
    const cnt = new Array(26).fill(0);
    for (const c of word) cnt[c.charCodeAt(0) - 97]++;
    const freqs = cnt.filter(x => x > 0).sort((a, b) => b - a);
    let total = 0;
    for (let i = 0; i < freqs.length; i++) total += freqs[i] * (Math.floor(i / 8) + 1);
    return total;
};
